#include <vector>
#include <algorithm>
#include <unordered_map>
#include <cmath>

long long solve(std::vector<long long> nums) {
    long long count = 0;
    int n = nums.size();
    std::unordered_map<long long, int> freq;

    for (int i = 0; i < n; ++i) {
        freq[nums[i]]++;
    }

    for (int i = 0; i < n; ++i) {
        for (int j = i + 1; j < n; ++j) {
            long long a = nums[i], b = nums[j];
            long long abs_a = std::abs(a);
            long long abs_b = std::abs(b);
            long long diff = std::abs(a - b);
            long long sum = std::abs(a + b);

            long long min_val = std::min(diff, sum);
            long long max_val = std::max(diff, sum);

            long long min_abs = std::min(abs_a, abs_b);
            long long max_abs = std::max(abs_a, abs_b);

            if (min_val <= min_abs && max_val >= max_abs) {
                count++;
            }
        }
    }

    return count;
}
